// =========================================================
// 1. CẤU HÌNH BIẾN
// =========================================================
const COL_NAME      = "fullName";
const COL_ID        = "id";
const COL_PHONE     = "phone";
const COL_EDU_SYS   = "system";
const COL_MAJOR     = "major";
const COL_ADVISOR   = "counselor";
const COL_N8N_TAG   = "n8n_status";
const COL_TOTAL     = "total_money";      
const COL_SCHOLARSHIP = "scholarship";    
const COL_NOTE      = "note";             
const COL_SOURCE    = "source";           

const PAYMENT_DOTS = [
    { id: '1', amount: 'deposit_money', status: 'valid1', proof: 'deposit_link', label: 'Tiền Cọc' },
    { id: '2', amount: 'l1_money',      status: 'valid2', proof: 'l1_link',      label: 'Đợt 1' },
    { id: '3', amount: 'bs3',           status: 'valid3', proof: 'bill3',        label: 'Bổ sung 3' },
    { id: '4', amount: 'bs4',           status: 'valid4', proof: 'bill4',        label: 'Bổ sung 4' },
    { id: '5', amount: 'bs5',           status: 'valid5', proof: 'bill5',        label: 'Bổ sung 5' }
];

function formatVN(val) {
    if (!val) return "0 VNĐ";
    let n = parseInt(String(val).replace(/\D/g, '')) || 0;
    return n.toLocaleString('vi-VN') + "đ";
}

function parseNumber(val) {
    if (!val) return 0;
    return parseInt(String(val).replace(/\D/g, '')) || 0;
}

const rawInput = $input.item.json;
const payload = rawInput.body || rawInput;
const dataSub = payload.full_data || payload.data || {};

function getVal(key) { return payload[key] || dataSub[key] || ""; }

const rowIndex = getVal("row_index") || getVal("row_number");
const sentStatusStr = getVal(COL_N8N_TAG).toString();
let currentTags = sentStatusStr.split(',').map(s => s.trim()).filter(s => s !== "");

const totalMoneyRaw = parseNumber(getVal(COL_TOTAL));
const totalMoneyFmt = formatVN(totalMoneyRaw);

// =========================================================
// 2. MÀU SẮC CHO CÁC MỐC QUAN TRỌNG (MILESTONES)
// =========================================================
const eduSysStr = getVal(COL_EDU_SYS).toString().toUpperCase();
const is9Plus = eduSysStr.includes("9+");
let milestoneHtml = "";

if (is9Plus && totalMoneyRaw >= 2000000) {
    milestoneHtml = "🏆 <font color=\"#0984E3\"><b>ĐÃ HOÀN THIỆN CỌC (HỆ 9+)</b></font>";
} else if (!is9Plus && totalMoneyRaw >= 1000000) {
    milestoneHtml = "🏆 <font color=\"#0984E3\"><b>ĐÃ HOÀN THIỆN CỌC</b></font>";
} else if (totalMoneyRaw >= 150000) {
    milestoneHtml = "🏅 <font color=\"#8E44AD\"><b>ĐÃ HOÀN THIỆN LPXT (Chưa đủ Cọc)</b></font>";
} else {
    milestoneHtml = "⏳ <font color=\"#7F8C8D\"><b>Tiến độ: Chưa đủ mốc LPXT/Cọc</b></font>";
}

const results = [];
let hasUpdate = false;

PAYMENT_DOTS.forEach((dot) => {
    const value = getVal(dot.amount).toString().trim();
    const rawStatus = getVal(dot.status).toString();
    const accountingValue = rawStatus.trim().toUpperCase();
    const proofUrl = getVal(dot.proof);

    if (value !== "" && value !== "0") {
        const name  = getVal(COL_NAME) || "N/A";
        const idSV  = getVal(COL_ID) || "N/A";
        const moneyFormatted = formatVN(value);
        const adv   = getVal(COL_ADVISOR) || "N/A";
        const eduSys  = getVal(COL_EDU_SYS) || "---";
        const major   = getVal(COL_MAJOR) || "---";
        const scholar = getVal(COL_SCHOLARSHIP) || "Không";

        const noteText = getVal(COL_NOTE).toString().trim();
        // Nhấn mạnh Ghi chú bằng màu Đỏ sậm
        const noteHtml = noteText ? `<br>📝 <b>Lưu ý:</b> <font color="#C0392B"><i>${noteText}</i></font>` : "";
        let sourceText = getVal(COL_SOURCE).toString().trim() || "Chưa rõ nguồn";
        const sourceHtml = `<br>🎯 <b>Nguồn:</b> <font color="#8E44AD">${sourceText}</font>`;

        const confirmKey = `confirm${dot.id}`;
        const okKey      = `ok${dot.id}`;
        const noKey      = `no${dot.id}`;

        let cardPayload = null;
        let newTag = "";

        const ICON_CHECK = "https://img.icons8.com/color/48/checked--v1.png";
        const ICON_WARN  = "https://img.icons8.com/color/48/error--v1.png";
        const ICON_BELL  = "https://img.icons8.com/color/48/bell.png";

        // =========================================================
        // 3. TẠO NỘI DUNG CARD VỚI THANH MÀU NHẤN NHÁ (ACCENT BARS)
        // =========================================================

        if (accountingValue.includes("ĐỒNG Ý") || accountingValue.includes("OK")) {
            // ✅ KẾ TOÁN XÁC NHẬN -> MÀU XANH LÁ
            if (!currentTags.includes(okKey)) {
                newTag = okKey;
                // Tạo dải ruy băng Xanh lá ở đỉnh thẻ
                let content = `<font color="#27AE60">▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀</font><br>` +
                              `🎉 <font color="#27AE60"><b>GIAO DỊCH ĐÃ ĐƯỢC DUYỆT THÀNH CÔNG</b></font><br><br>` +
                              `👤 <b>Sinh viên:</b> <font color="#2980B9"><b>${name}</b></font> <font color="#7F8C8D">(${idSV})</font><br>` +
                              `💵 <b>Số tiền duyệt:</b> <font color="#27AE60"><b>${moneyFormatted}</b></font>` +
                              `${noteHtml}<br>` +
                              `<font color="#BDC3C7">━━━━━━━━━━━━━</font><br>` +
                              `💰 <b><font color="#16A085">TỔNG ĐÃ NỘP:</font></b> <font color="#16A085"><b>${totalMoneyFmt}</b></font>`;

                cardPayload = createGoogleCard("✅ KẾ TOÁN XÁC NHẬN: " + dot.label, "Trạng thái: Hoàn tất", ICON_CHECK, content, proofUrl, milestoneHtml, false);
            }
        }
        else if (accountingValue.includes("KHÔNG") || accountingValue.includes("TỪ CHỐI")) {
            // ❌ KẾ TOÁN TỪ CHỐI -> MÀU ĐỎ ĐẬM
            if (!currentTags.includes(noKey)) {
                newTag = noKey;
                // Tạo dải ruy băng Đỏ đậm ở đỉnh thẻ
                let content = `<font color="#C0392B">▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀</font><br>` +
                              `⚠️ <font color="#C0392B"><b>KẾ TOÁN ĐÃ TỪ CHỐI BÁO PHÍ NÀY!</b></font><br><br>` +
                              `👤 <b>Sinh viên:</b> <font color="#2980B9"><b>${name}</b></font> <font color="#7F8C8D">(${idSV})</font><br>` +
                              `💸 <b>Số tiền báo:</b> <font color="#C0392B"><b>${moneyFormatted}</b></font>` +
                              `${noteHtml}<br>` +
                              `<font color="#BDC3C7">━━━━━━━━━━━━━</font><br>` +
                              `👉 <b>Yêu cầu xử lý:</b> TVV <font color="#E67E22"><b>${adv}</b></font> kiểm tra lại ngay!`;

                cardPayload = createGoogleCard("❌ CẢNH BÁO TỪ CHỐI: " + dot.label, "Trạng thái: Cần xử lý", ICON_WARN, content, proofUrl, "", true);
            }
        }
        else {
            // 🚨 TVV GỬI DUYỆT -> MÀU CAM / ĐỎ TƯƠI
            if (!currentTags.includes(confirmKey) && !currentTags.includes(okKey) && !currentTags.includes(noKey)) {
                newTag = confirmKey;
                // Tạo dải ruy băng Cam ở đỉnh thẻ
                let content = `<font color="#E67E22">▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀</font><br>` +
                              `🔔 <font color="#E67E22"><b>TƯ VẤN VIÊN GỬI YÊU CẦU DUYỆT PHÍ</b></font><br><br>` +
                              `👨‍💼 <b>TVV:</b> <font color="#D35400"><b>${adv}</b></font><br>` +
                              `👤 <b>Sinh viên:</b> <font color="#2980B9"><b>${name}</b></font> <font color="#7F8C8D">(${idSV})</font><br>` +
                              `🏫 <b>Hệ:</b> ${eduSys}  |  <b>Ngành:</b> ${major}<br>` +
                              `🎁 <b>Học bổng:</b> <font color="#8E44AD"><b>${scholar}</b></font><br><br>` +
                              `💸 <b>ĐỢT NÀY NỘP:</b> <font color="#E74C3C"><b>${moneyFormatted}</b></font>` +
                              `${sourceHtml}${noteHtml}<br>` +
                              `<font color="#BDC3C7">━━━━━━━━━━━━━</font><br>` +
                              `💰 <b><font color="#D35400">TỔNG ĐÃ NỘP:</font></b> <font color="#D35400"><b>${totalMoneyFmt}</b></font>`;

                cardPayload = createGoogleCard("🚨 CẦN XÁC NHẬN: " + dot.label, "Đề nghị kế toán tra soát", ICON_BELL, content, proofUrl, milestoneHtml, true);
            }
        }

        if (cardPayload) {
            currentTags.push(newTag); 
            results.push({
                json: { google_chat_payload: cardPayload, studentId: idSV, row_number: rowIndex, new_status_value: currentTags.join(',') }
            });
            hasUpdate = true;
        }
    }
});

// =========================================================
// 4. HÀM ĐÓNG GÓI THẺ CARD
// =========================================================
function createGoogleCard(title, subtitle, iconUrl, contentHtml, proofUrl, milestoneHtml, showButton) {
    const widgets = [];
    widgets.push({ "textParagraph": { "text": contentHtml } });

    if (showButton && proofUrl) {
        widgets.push({ "buttonList": { "buttons": [ { "text": "👉 XEM MINH CHỨNG", "icon": { "iconUrl": "https://img.icons8.com/ios-glyphs/30/link--v1.png" }, "onClick": { "openLink": { "url": proofUrl } } } ] } });
    } else if (showButton && !proofUrl) {
         widgets.push({ "textParagraph": { "text": "<font color=\"#C0392B\"><i>⚠️ Không đính kèm link minh chứng</i></font>" } });
    }

    if (milestoneHtml) {
        // Đặt mốc Milestone vào một khối tách biệt ở dưới cùng
        widgets.push({ "textParagraph": { "text": "<font color=\"#BDC3C7\">━━━━━━━━━━━━━</font><br>" + milestoneHtml } });
    }

    return { "cardsV2": [ { "cardId": "unique-card-id-" + Math.random(), "card": { "header": { "title": title, "subtitle": subtitle, "imageUrl": iconUrl, "imageType": "CIRCLE" }, "sections": [ { "widgets": widgets } ] } } ] };
}

if (!hasUpdate) return [];
return results;

const payload = $input.item.json.body || $input.item.json;
let cardPayload = {};

// ÉP MÚI GIỜ VIỆT NAM (GMT+7)
const options = { timeZone: 'Asia/Ho_Chi_Minh', hour: '2-digit', minute: '2-digit', hour12: false };
const currentTime = new Date().toLocaleTimeString('vi-VN', options);

if (payload.date) {
    // =======================================================
    // BÁO CÁO NGÀY (Lấy giao diện trực tiếp từ Apps Script)
    // =======================================================
    cardPayload = {
        "cardsV2": [{
            "cardId": "daily-" + Date.now(),
            "card": {
                "header": { 
                    "title": "📊 BÁO CÁO TỔNG KẾT NGÀY", 
                    "subtitle": "Cập nhật lúc: " + currentTime, 
                    "imageUrl": "https://img.icons8.com/color/48/combo-chart--v1.png", 
                    "imageType": "CIRCLE" 
                },
                "sections": [{
                    "widgets": [{
                        "textParagraph": {
                            "text": payload.dailyDetailHtml // <-- Chỉ cần gọi đúng 1 dòng này!
                        }
                    }]
                }]
            }
        }]
    };
} else if (payload.month) {
    // =======================================================
    // BÁO CÁO THÁNG
    // =======================================================
    cardPayload = {
        "cardsV2": [{
            "cardId": "monthly-" + Date.now(),
            "card": {
                "header": { "title": "🏆 BÁO CÁO TỔNG KẾT THÁNG", "subtitle": "Tháng " + payload.month, "imageUrl": "https://img.icons8.com/fluency/48/trophy.png", "imageType": "CIRCLE" },
                "sections": [{
                    "widgets": [{
                        "textParagraph": {
                            "text": `<b>🔸 Tổng NB toàn tháng:</b> <font color="#ffaa00\"><b>${payload.nbMonth || 0}</b></font><br><b>🔹 Tổng LPXT toàn tháng:</b> <font color=\"#0056b3\"><b>${payload.lpxtMonth || 0}</b></font><br><b>⭐ Tổng hoàn thiện cọc:</b> <font color=\"#198754\"><b>${payload.neMonth || 0}</b></font><br>----------------<br>🥇 <b>BEST SELLER THÁNG:</b><br><font color=\"#e67e22\"><b>${payload.topTvvName || 'Chưa có'}</b></font> (${payload.topTvvCount || 0} NE)`
                        }
                    }]
                }]
            }
        }]
    };
}

return { json: { google_chat_payload: cardPayload } };
